sysmlv2:
package VehicleModel {
   part def Engine;
   part def Wheel;

   part def Vehicle {
      part engine : Engine;
      part wheels[4] : Wheel;
   }
}

package PowerSystem {

   port def PowerPort;

   part def Battery {
      port out : PowerPort;
   }

   part def Motor {
      port in : PowerPort;
   }

   part system {
      connect battery.out to motor.in;
   }

}
